import{_ as s,o as e,c as n,a as l}from"./app.978316e1.js";const u=JSON.parse('{"title":"Java线上排错神器Arthas实战指南：无需重启，搞定80%线上疑难问题","description":"","frontmatter":{},"headers":[{"level":2,"title":"一、Arthas 核心优势","slug":"一、arthas-核心优势","link":"#一、arthas-核心优势","children":[]},{"level":2,"title":"二、快速安装与启动（生产通用）","slug":"二、快速安装与启动-生产通用","link":"#二、快速安装与启动-生产通用","children":[{"level":3,"title":"1. 下载Arthas启动包","slug":"_1-下载arthas启动包","link":"#_1-下载arthas启动包","children":[]},{"level":3,"title":"2. 启动并挂载Java进程","slug":"_2-启动并挂载java进程","link":"#_2-启动并挂载java进程","children":[]},{"level":3,"title":"3. 退出命令","slug":"_3-退出命令","link":"#_3-退出命令","children":[]}]},{"level":2,"title":"三、核心实战：Watch命令（最常用、最实用）","slug":"三、核心实战-watch命令-最常用、最实用","link":"#三、核心实战-watch命令-最常用、最实用","children":[{"level":3,"title":"场景背景","slug":"场景背景","link":"#场景背景","children":[]},{"level":3,"title":"1. 基础监控：外层业务方法","slug":"_1-基础监控-外层业务方法","link":"#_1-基础监控-外层业务方法","children":[]},{"level":3,"title":"2. 高阶实战：监控方法内部 RestTemplate 调用","slug":"_2-高阶实战-监控方法内部-resttemplate-调用","link":"#_2-高阶实战-监控方法内部-resttemplate-调用","children":[]},{"level":3,"title":"3. Watch常用过滤技巧","slug":"_3-watch常用过滤技巧","link":"#_3-watch常用过滤技巧","children":[]}]},{"level":2,"title":"四、Arthas 高频实用命令（线上必备）","slug":"四、arthas-高频实用命令-线上必备","link":"#四、arthas-高频实用命令-线上必备","children":[{"level":3,"title":"1. trace：追踪方法内部耗时（解决接口超时）","slug":"_1-trace-追踪方法内部耗时-解决接口超时","link":"#_1-trace-追踪方法内部耗时-解决接口超时","children":[]},{"level":3,"title":"2. dashboard：JVM全局监控面板","slug":"_2-dashboard-jvm全局监控面板","link":"#_2-dashboard-jvm全局监控面板","children":[]},{"level":3,"title":"3. thread：定位CPU飙高线程","slug":"_3-thread-定位cpu飙高线程","link":"#_3-thread-定位cpu飙高线程","children":[]},{"level":3,"title":"4. jad：线上反编译代码","slug":"_4-jad-线上反编译代码","link":"#_4-jad-线上反编译代码","children":[]},{"level":3,"title":"5. redefine：热更新代码","slug":"_5-redefine-热更新代码","link":"#_5-redefine-热更新代码","children":[]}]},{"level":2,"title":"五、真实线上排查案例总结","slug":"五、真实线上排查案例总结","link":"#五、真实线上排查案例总结","children":[{"level":3,"title":"案例1：第三方接口偶现返回空值","slug":"案例1-第三方接口偶现返回空值","link":"#案例1-第三方接口偶现返回空值","children":[]},{"level":3,"title":"案例2：接口间歇性超时","slug":"案例2-接口间歇性超时","link":"#案例2-接口间歇性超时","children":[]},{"level":3,"title":"案例3：参数传递异常","slug":"案例3-参数传递异常","link":"#案例3-参数传递异常","children":[]}]},{"level":2,"title":"六、使用注意事项（生产必看）","slug":"六、使用注意事项-生产必看","link":"#六、使用注意事项-生产必看","children":[]},{"level":2,"title":"七、总结","slug":"七、总结","link":"#七、总结","children":[]}],"relativePath":"Java/Java线上排错神器Arthas实战指南.md","lastUpdated":1779518739447}'),r={name:"Java/Java线上排错神器Arthas实战指南.md"};function p(t,a,o,i,c,d){return e(),n("div",{"data-pagefind-body":!0},[...a[0]||(a[0]=[l(`<h1 id="java线上排错神器arthas实战指南-无需重启-搞定80-线上疑难问题" tabindex="-1">Java线上排错神器Arthas实战指南：无需重启，搞定80%线上疑难问题 <a class="header-anchor" href="#java线上排错神器arthas实战指南-无需重启-搞定80-线上疑难问题" aria-hidden="true">#</a></h1><p>### 前言</p><p>线上Java应用最头疼的问题是什么？</p><p>接口偶尔超时、参数传递异常、第三方接口调用失败、方法返回值诡异、CPU突高、内存泄漏…</p><p>传统排查方式：打日志、重新打包、重启服务、等待复现，不仅流程繁琐，还会影响线上业务稳定性。</p><p>而 <strong>Arthas</strong>（阿里开源Java诊断工具）完美解决了这个痛点：<strong>无需修改代码、无需重启服务、无侵入</strong>，实时监控方法入参、返回值、异常、执行耗时，精准定位线上问题根源，是后端开发者必备的线上排错神器。</p><p>本文结合<strong>真实业务实操场景</strong>，从零讲解Arthas安装、基础命令、高频实战技巧，重点解决大家最常用的「监控方法内部调用、排查第三方HTTP请求异常」场景，看完直接上手落地。</p><hr><h2 id="一、arthas-核心优势" tabindex="-1">一、Arthas 核心优势 <a class="header-anchor" href="#一、arthas-核心优势" aria-hidden="true">#</a></h2><ul><li><p><strong>无侵入诊断</strong>：基于Java Agent字节码增强，不修改业务代码、无需重启服务</p></li><li><p><strong>功能全覆盖</strong>：支持方法监控、耗时追踪、线程排查、内存分析、热更新代码</p></li><li><p><strong>轻量高效</strong>：Jar包体积小，低性能损耗，适配生产环境</p></li><li><p><strong>落地性强</strong>：专治线上偶现bug、接口超时、参数异常、第三方调用失败等疑难问题</p></li></ul><hr><h2 id="二、快速安装与启动-生产通用" tabindex="-1">二、快速安装与启动（生产通用） <a class="header-anchor" href="#二、快速安装与启动-生产通用" aria-hidden="true">#</a></h2><h3 id="_1-下载arthas启动包" tabindex="-1">1. 下载Arthas启动包 <a class="header-anchor" href="#_1-下载arthas启动包" aria-hidden="true">#</a></h3><p>服务器直接执行命令下载，一次下载永久使用：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">curl</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-O</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">https://arthas.aliyun.com/arthas-boot.jar</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-启动并挂载java进程" tabindex="-1">2. 启动并挂载Java进程 <a class="header-anchor" href="#_2-启动并挂载java进程" aria-hidden="true">#</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">java</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-jar</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">arthas-boot.jar</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>执行后会列出当前服务器所有Java进程，<strong>输入目标业务进程序号，回车</strong>，即可进入Arthas交互式控制台。</p><blockquote><p><strong>小贴士</strong>：生产环境建议避开流量高峰期操作，Arthas挂载对服务性能损耗极低，可放心使用。</p></blockquote><h3 id="_3-退出命令" tabindex="-1">3. 退出命令 <a class="header-anchor" href="#_3-退出命令" aria-hidden="true">#</a></h3><ul><li><p>临时退出控制台：<code>quit</code>（保留挂载进程）</p></li><li><p>彻底关闭Arthas：<code>stop</code>（释放资源，结束挂载）</p></li></ul><hr><h2 id="三、核心实战-watch命令-最常用、最实用" tabindex="-1">三、核心实战：Watch命令（最常用、最实用） <a class="header-anchor" href="#三、核心实战-watch命令-最常用、最实用" aria-hidden="true">#</a></h2><p><strong>watch</strong> 是Arthas使用率最高的命令，核心作用：<strong>实时监控方法入参、返回值、异常、执行链路</strong>。</p><p>很多新手只会监控外层方法，却不会排查<strong>方法内部调用的第三方接口</strong>，这也是线上排查的核心痛点，下面结合真实业务场景手把手教学。</p><h3 id="场景背景" tabindex="-1">场景背景 <a class="header-anchor" href="#场景背景" aria-hidden="true">#</a></h3><p>业务类：<code>com\\.demdm\\.app\\.module\\.auth\\.service\\.AuthCodeService</code></p><p>业务方法：<code>requestUserAccount</code></p><p>问题：该方法内部通过 <code>restTemplate\\.exchange</code> 调用第三方HTTP接口，偶现调用失败、返回数据异常，日志打印不全，无法定位问题。</p><h3 id="_1-基础监控-外层业务方法" tabindex="-1">1. 基础监控：外层业务方法 <a class="header-anchor" href="#_1-基础监控-外层业务方法" aria-hidden="true">#</a></h3><p>先监控外层方法的完整执行信息（入参、返回值、异常），快速判断方法本身是否异常：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">watch</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">com.demdm.app.module.auth.service.AuthCodeService</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">requestUserAccount</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{params,returnObj,throwExp}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-x</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>参数解析</strong>：</p><ul><li><p><code>params</code>：捕获方法所有入参</p></li><li><p><code>returnObj</code>：捕获方法返回值</p></li><li><p><code>throwExp</code>：捕获方法抛出的所有异常</p></li><li><p><code>\\-x 3</code>：展开对象3层嵌套（解决参数/返回值对象嵌套看不到详情问题）</p></li></ul><h3 id="_2-高阶实战-监控方法内部-resttemplate-调用" tabindex="-1">2. 高阶实战：监控方法内部 RestTemplate 调用 <a class="header-anchor" href="#_2-高阶实战-监控方法内部-resttemplate-调用" aria-hidden="true">#</a></h3><p>重点！！！外层方法无报错，但<strong>内部第三方HTTP请求异常</strong>，直接监控内部的 <code>restTemplate\\.exchange</code> 方法，精准抓取请求全量信息：</p><h4 id="通用监控-全局捕获" tabindex="-1">通用监控（全局捕获） <a class="header-anchor" href="#通用监控-全局捕获" aria-hidden="true">#</a></h4><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">watch</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">org.springframework.web.client.RestTemplate</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">exchange</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{params,returnObj,throwExp}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-x</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="精准监控-只捕获当前业务类调用" tabindex="-1">精准监控（只捕获当前业务类调用） <a class="header-anchor" href="#精准监控-只捕获当前业务类调用" aria-hidden="true">#</a></h4><p>避免监控到项目中其他模块的RestTemplate请求，精准过滤目标业务调用：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">watch</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">org.springframework.web.client.RestTemplate</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">exchange</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{params,returnObj,throwExp}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-x</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-n</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">10</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">clazz@class.name.contains(&quot;AuthCodeService&quot;)</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>执行后可获取的核心信息</strong>：</p><ul><li><p>第三方接口真实请求URL、请求方式（GET/POST）</p></li><li><p>完整请求头、请求体参数</p></li><li><p>接口响应状态码、响应体数据</p></li><li><p>HTTP调用超时、连接异常、参数不匹配等报错信息</p></li></ul><h3 id="_3-watch常用过滤技巧" tabindex="-1">3. Watch常用过滤技巧 <a class="header-anchor" href="#_3-watch常用过滤技巧" aria-hidden="true">#</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 只监控执行耗时超过100ms的请求（排查接口超时）</span></span>
<span class="line"><span style="color:#FFCB6B;">watch</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">全类名</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">方法名</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{params,returnObj}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">cost&gt;100</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-x</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 只监控抛出异常的请求（专注排查报错）</span></span>
<span class="line"><span style="color:#FFCB6B;">watch</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">全类名</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">方法名</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{params,throwExp}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-e</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-x</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 只捕获10次请求后自动停止（避免日志刷屏）</span></span>
<span class="line"><span style="color:#FFCB6B;">watch</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">全类名</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">方法名</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{params,returnObj}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-n</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">10</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-x</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="四、arthas-高频实用命令-线上必备" tabindex="-1">四、Arthas 高频实用命令（线上必备） <a class="header-anchor" href="#四、arthas-高频实用命令-线上必备" aria-hidden="true">#</a></h2><h3 id="_1-trace-追踪方法内部耗时-解决接口超时" tabindex="-1">1. trace：追踪方法内部耗时（解决接口超时） <a class="header-anchor" href="#_1-trace-追踪方法内部耗时-解决接口超时" aria-hidden="true">#</a></h3><p>精准定位方法内部哪一段代码、哪个外部调用耗时最长，专治接口慢查询、超时问题：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">trace</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">com.demdm.app.module.auth.service.AuthCodeService</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">requestUserAccount</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-dashboard-jvm全局监控面板" tabindex="-1">2. dashboard：JVM全局监控面板 <a class="header-anchor" href="#_2-dashboard-jvm全局监控面板" aria-hidden="true">#</a></h3><p>实时查看CPU、内存、线程、GC状态，快速排查服务卡顿、CPU飙高、频繁GC问题：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">dashboard</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-thread-定位cpu飙高线程" tabindex="-1">3. thread：定位CPU飙高线程 <a class="header-anchor" href="#_3-thread-定位cpu飙高线程" aria-hidden="true">#</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 查看最繁忙的3个线程堆栈</span></span>
<span class="line"><span style="color:#FFCB6B;">thread</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-n</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">3</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_4-jad-线上反编译代码" tabindex="-1">4. jad：线上反编译代码 <a class="header-anchor" href="#_4-jad-线上反编译代码" aria-hidden="true">#</a></h3><p>直接反编译线上运行的class文件，确认线上代码是否和本地一致，解决「本地正常线上异常」问题：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">jad</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">com.demdm.app.module.auth.service.AuthCodeService</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_5-redefine-热更新代码" tabindex="-1">5. redefine：热更新代码 <a class="header-anchor" href="#_5-redefine-热更新代码" aria-hidden="true">#</a></h3><p>紧急线上bug无需重启服务，直接替换class文件热修复，快速恢复业务：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">redefine</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">/tmp/修改后的类.class</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="五、真实线上排查案例总结" tabindex="-1">五、真实线上排查案例总结 <a class="header-anchor" href="#五、真实线上排查案例总结" aria-hidden="true">#</a></h2><h3 id="案例1-第三方接口偶现返回空值" tabindex="-1">案例1：第三方接口偶现返回空值 <a class="header-anchor" href="#案例1-第三方接口偶现返回空值" aria-hidden="true">#</a></h3><p><strong>问题</strong>：业务方法无报错，但数据偶尔缺失，日志无详细记录</p><p><strong>排查方案</strong>：watch监控RestTemplate.exchange，发现第三方接口偶尔返回502，无重试机制导致数据为空</p><p><strong>解决方案</strong>：添加接口重试、异常兜底逻辑</p><h3 id="案例2-接口间歇性超时" tabindex="-1">案例2：接口间歇性超时 <a class="header-anchor" href="#案例2-接口间歇性超时" aria-hidden="true">#</a></h3><p><strong>问题</strong>：接口大部分时间正常，偶尔超时告警</p><p><strong>排查方案</strong>：trace追踪方法耗时，定位是第三方HTTP接口响应不稳定导致</p><p><strong>解决方案</strong>：优化超时时间、增加熔断降级策略</p><h3 id="案例3-参数传递异常" tabindex="-1">案例3：参数传递异常 <a class="header-anchor" href="#案例3-参数传递异常" aria-hidden="true">#</a></h3><p><strong>问题</strong>：业务逻辑判断异常，找不到参数问题</p><p><strong>排查方案</strong>：watch捕获方法入参，发现前端传递空参数未做校验</p><hr><h2 id="六、使用注意事项-生产必看" tabindex="-1">六、使用注意事项（生产必看） <a class="header-anchor" href="#六、使用注意事项-生产必看" aria-hidden="true">#</a></h2><ol><li><p><strong>避免长时间监控</strong>：问题定位后及时stop/quit，长期监控会产生大量日志</p></li><li><p><strong>展开层数适度</strong>：常规场景用<code>\\-x 3</code>，嵌套极深的对象再调到4，层数过高会刷屏</p></li><li><p><strong>精准过滤</strong>：多模块项目尽量添加类名、次数过滤，避免监控无关请求</p></li><li><p><strong>禁止线上随意热更新核心类</strong>：热更新仅用于紧急bug修复，更新后需后续版本迭代固化代码</p></li></ol><hr><h2 id="七、总结" tabindex="-1">七、总结 <a class="header-anchor" href="#七、总结" aria-hidden="true">#</a></h2><p>Arthas 之所以成为Java开发者的线上排错神器，核心就是<strong>高效、无侵入、全覆盖</strong>。</p><p>掌握核心用法：</p><ul><li><p><strong>参数/返回值异常</strong> → watch 命令</p></li><li><p><strong>接口超时、耗时过长</strong> → trace 命令</p></li><li><p><strong>CPU、线程异常</strong> → dashboard + thread 命令</p></li><li><p><strong>线上代码不一致</strong> → jad 反编译</p></li><li><p><strong>紧急bug修复</strong> → redefine 热更新</p></li></ul><p>尤其是<strong>监控方法内部第三方调用</strong>的实操技巧，完美解决了线上日志不全、无法定位外部接口问题的痛点，日常开发、线上运维都能高频复用。</p><blockquote><p>（注：文档部分内容可能由 AI 生成）</p></blockquote>`,84)])])}const b=s(r,[["render",p]]);export{u as __pageData,b as default};
